import React from 'react';
import { Container } from 'react-bootstrap'; 
// Componentes dependientes
import SearchBox from './SearchBox';

// NOTA: Para este test, eliminamos todos los hooks y dependencias de contexto 
// para que el componente se renderice solo con la SearchBox.

const Header = () => {
  // CRÍTICO: Añadimos rounded-b-xl para redondear las esquinas inferiores
  return (
    <header 
      className="w-full sticky top-0 z-50 transition-all duration-300 shadow-md rounded-b-xl"
      style={{ backgroundColor: 'var(--brand-dark)' }} 
    >
      {/* py-3 para dar espacio arriba y abajo */}
      <Container className="py-3"> 
        
        {/* Contenedor principal para centrar la barra de búsqueda */}
        <div className="flex justify-center items-center w-full"> 
          
          {/* Barra de búsqueda (Centrada) */}
          {/* Usamos w-full para que ocupe todo el ancho del Container, 
             y max-w-lg para limitar el ancho y mx-auto para centrar. */}
          <div className="w-full max-w-xl">
            <SearchBox /> 
          </div>
          
        </div>
        
      </Container>
    </header>
  );
};

export default Header;
